/**
 * Tests for src/lib/performance/web-vitals.ts
 *
 * Tests all pure utility functions: getRating, buildMetric, formatMetricValue,
 * ratingColor, metricToScore, computeOverallScore, summariseMetrics, etc.
 */

import {
  getRating,
  buildMetric,
  formatMetricValue,
  ratingColor,
  metricToScore,
  computeOverallScore,
  summariseMetrics,
  VITAL_THRESHOLDS,
  METRIC_WEIGHTS,
  type WebVitalName,
  type WebVitalRating,
} from '@/lib/performance/web-vitals';

// ============================================================================
// getRating
// ============================================================================

describe('getRating', () => {
  it('returns "good" when value is below good threshold', () => {
    expect(getRating('LCP', 2000)).toBe('good');
    expect(getRating('CLS', 0.05)).toBe('good');
    expect(getRating('FID', 50)).toBe('good');
  });

  it('returns "good" when value equals good threshold', () => {
    expect(getRating('LCP', 2500)).toBe('good');
    expect(getRating('CLS', 0.1)).toBe('good');
    expect(getRating('INP', 200)).toBe('good');
  });

  it('returns "needs-improvement" between good and poor', () => {
    expect(getRating('LCP', 3000)).toBe('needs-improvement');
    expect(getRating('CLS', 0.2)).toBe('needs-improvement');
    expect(getRating('FID', 200)).toBe('needs-improvement');
    expect(getRating('INP', 350)).toBe('needs-improvement');
  });

  it('returns "needs-improvement" when value equals poor threshold', () => {
    expect(getRating('LCP', 4000)).toBe('needs-improvement');
    expect(getRating('CLS', 0.25)).toBe('needs-improvement');
  });

  it('returns "poor" when value exceeds poor threshold', () => {
    expect(getRating('LCP', 5000)).toBe('poor');
    expect(getRating('CLS', 0.5)).toBe('poor');
    expect(getRating('FID', 500)).toBe('poor');
    expect(getRating('INP', 600)).toBe('poor');
  });

  it('returns "good" for zero value', () => {
    expect(getRating('LCP', 0)).toBe('good');
    expect(getRating('CLS', 0)).toBe('good');
  });

  it('handles FCP and TTFB', () => {
    expect(getRating('FCP', 1500)).toBe('good');
    expect(getRating('FCP', 2500)).toBe('needs-improvement');
    expect(getRating('FCP', 4000)).toBe('poor');
    expect(getRating('TTFB', 500)).toBe('good');
    expect(getRating('TTFB', 1000)).toBe('needs-improvement');
    expect(getRating('TTFB', 2000)).toBe('poor');
  });
});

// ============================================================================
// buildMetric
// ============================================================================

describe('buildMetric', () => {
  it('creates a metric with correct fields', () => {
    const metric = buildMetric('LCP', 2345.6789, 'reload');
    expect(metric.name).toBe('LCP');
    expect(metric.value).toBe(2345.679); // rounded to 3 dp
    expect(metric.rating).toBe('good');
    expect(metric.navigationType).toBe('reload');
    expect(typeof metric.timestamp).toBe('number');
  });

  it('defaults navigationType to "navigate"', () => {
    const metric = buildMetric('CLS', 0.05);
    expect(metric.navigationType).toBe('navigate');
  });

  it('assigns correct rating', () => {
    const poor = buildMetric('LCP', 5000);
    expect(poor.rating).toBe('poor');
    const good = buildMetric('CLS', 0.01);
    expect(good.rating).toBe('good');
  });

  it('rounds value to 3 decimal places', () => {
    const metric = buildMetric('CLS', 0.12345678);
    expect(metric.value).toBe(0.123);
  });
});

// ============================================================================
// formatMetricValue
// ============================================================================

describe('formatMetricValue', () => {
  it('formats CLS with 3 decimal places', () => {
    expect(formatMetricValue('CLS', 0.1)).toBe('0.100');
    expect(formatMetricValue('CLS', 0.05)).toBe('0.050');
    expect(formatMetricValue('CLS', 0.256)).toBe('0.256');
  });

  it('formats timing metrics in ms', () => {
    expect(formatMetricValue('LCP', 2500)).toBe('2500ms');
    expect(formatMetricValue('FID', 99.7)).toBe('100ms');
    expect(formatMetricValue('INP', 200)).toBe('200ms');
    expect(formatMetricValue('FCP', 1800)).toBe('1800ms');
    expect(formatMetricValue('TTFB', 300.4)).toBe('300ms');
  });
});

