// ============================================================================
// metricToScore
// ============================================================================

describe('metricToScore', () => {
  it('returns 100 for values at or below good threshold', () => {
    expect(metricToScore('LCP', 2500)).toBe(100);
    expect(metricToScore('LCP', 1000)).toBe(100);
    expect(metricToScore('CLS', 0.1)).toBe(100);
  });

  it('returns 0 for values at or above poor threshold', () => {
    expect(metricToScore('LCP', 4000)).toBe(0);
    expect(metricToScore('LCP', 5000)).toBe(0);
    expect(metricToScore('CLS', 0.25)).toBe(0);
  });

  it('returns 50 for midpoint values', () => {
    // LCP: good=2500, poor=4000, mid=3250
    expect(metricToScore('LCP', 3250)).toBe(50);
    // CLS: good=0.1, poor=0.25, mid=0.175
    expect(metricToScore('CLS', 0.175)).toBe(50);
  });

  it('returns intermediate scores', () => {
    // LCP: good=2500, poor=4000 → at 3000, ratio = 500/1500 = 0.333 → score = 67
    expect(metricToScore('LCP', 3000)).toBe(67);
  });
});

// ============================================================================
// computeOverallScore
// ============================================================================

describe('computeOverallScore', () => {
  it('returns 100 for all-good metrics', () => {
    const score = computeOverallScore({
      LCP: 2000,
      INP: 100,
      CLS: 0.05,
      FCP: 1500,
      TTFB: 500,
    });
    expect(score).toBe(100);
  });

  it('returns 0 for all-poor metrics', () => {
    const score = computeOverallScore({
      LCP: 5000,
      INP: 600,
      CLS: 0.5,
      FCP: 4000,
      TTFB: 2000,
    });
    expect(score).toBe(0);
  });

  it('handles partial metrics', () => {
    const score = computeOverallScore({ LCP: 2000 });
    expect(score).toBe(100);
  });

  it('returns 100 for empty metrics', () => {
    expect(computeOverallScore({})).toBe(100);
  });

  it('computes weighted average correctly', () => {
    // LCP=2500 (100), INP=200 (100), CLS=0.175 (50), FCP=1800 (100), TTFB=800 (100)
    // Weighted: 0.25*100 + 0.30*100 + 0.25*50 + 0.10*100 + 0.10*100 = 25+30+12.5+10+10 = 87.5 → 88
    const score = computeOverallScore({
      LCP: 2500,
      INP: 200,
      CLS: 0.175,
      FCP: 1800,
      TTFB: 800,
    });
    expect(score).toBe(88);
  });
});

// ============================================================================
// summariseMetrics
// ============================================================================

describe('summariseMetrics', () => {
  it('produces a human-readable summary', () => {
    const result = summariseMetrics({
      LCP: 2000,
      CLS: 0.05,
      FCP: 1500,
    });
    expect(result).toContain('LCP: 2000ms (good)');
    expect(result).toContain('CLS: 0.050 (good)');
    expect(result).toContain('FCP: 1500ms (good)');
    expect(result).toContain('Overall score: 100/100');
  });

  it('includes rating for poor metrics', () => {
    const result = summariseMetrics({ LCP: 5000 });
    expect(result).toContain('LCP: 5000ms (poor)');
  });

  it('handles empty metrics', () => {
    const result = summariseMetrics({});
    expect(result).toBe('Overall score: 100/100');
  });
});

// ============================================================================
// Constants
// ============================================================================

describe('VITAL_THRESHOLDS', () => {
  it('has thresholds for all 6 metrics', () => {
    const names: WebVitalName[] = ['CLS', 'FID', 'INP', 'LCP', 'FCP', 'TTFB'];
    for (const name of names) {
      expect(VITAL_THRESHOLDS[name]).toBeDefined();
      expect(VITAL_THRESHOLDS[name].good).toBeLessThan(VITAL_THRESHOLDS[name].poor);
    }
  });
});

describe('METRIC_WEIGHTS', () => {
  it('weights sum to 1.0', () => {
    const sum = Object.values(METRIC_WEIGHTS).reduce((a, b) => a + (b ?? 0), 0);
    expect(sum).toBeCloseTo(1.0);
  });

  it('includes LCP, INP, CLS, FCP, TTFB', () => {
    expect(METRIC_WEIGHTS.LCP).toBeDefined();
    expect(METRIC_WEIGHTS.INP).toBeDefined();
    expect(METRIC_WEIGHTS.CLS).toBeDefined();
    expect(METRIC_WEIGHTS.FCP).toBeDefined();
    expect(METRIC_WEIGHTS.TTFB).toBeDefined();
  });
});
